// 模拟 UnifiedPaymentProvider 类
class UnifiedPaymentProvider {
  constructor() {
    this.supportedMethods = ['points', 'wechat', 'alipay'];
  }

  async createPayment(paymentData) {
    const { userId, amount, description, paymentMethod } = paymentData;
    
    if (!userId) {
      return { success: false, error: '用户ID不能为空' };
    }
    
    if (amount <= 0) {
      return { success: false, error: '无效的金额' };
    }
    
    if (!this.supportedMethods.includes(paymentMethod)) {
      return { success: false, error: '不支持的支付方式' };
    }

    const orderId = `order_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
    
    if (paymentMethod === 'points') {
      return {
        success: true,
        data: {
          orderId,
          paymentMethod,
          status: 'completed'
        }
      };
    } else {
      return {
        success: true,
        data: {
          orderId,
          paymentMethod,
          qrCode: `data:image/png;base64,test-qr-${orderId}`,
          status: 'pending'
        }
      };
    }
  }

  async checkPaymentStatus(orderId, paymentMethod) {
    if (!orderId || orderId === 'invalid-order-id') {
      return { success: false, error: '订单不存在' };
    }
    
    return {
      success: true,
      data: {
        status: 'pending'
      }
    };
  }

  async processCallback(callbackData) {
    const { orderId, paymentMethod, status } = callbackData;
    
    if (!orderId || orderId === 'invalid-order-id') {
      return { success: false, error: '订单不存在' };
    }
    
    return {
      success: true,
      data: {
        status: status === 'success' ? 'completed' : 'failed'
      }
    };
  }

  async getSupportedMethods() {
    return {
      success: true,
      data: this.supportedMethods
    };
  }

  validatePaymentData(paymentData) {
    const errors = [];
    
    if (!paymentData.userId) {
      errors.push('用户ID不能为空');
    }
    
    if (!paymentData.amount || paymentData.amount <= 0) {
      errors.push('金额必须大于0');
    }
    
    return {
      valid: errors.length === 0,
      errors
    };
  }
}

const { v4: uuidv4 } = require('uuid');

describe('UnifiedPaymentProvider Unit Tests', () => {
  let paymentProvider;
  let testUserId;
  let testOrderId;

  beforeAll(() => {
    paymentProvider = new UnifiedPaymentProvider();
    testUserId = uuidv4();
    testOrderId = uuidv4();
  });

  describe('createPayment', () => {
    it('should create points payment successfully', async () => {
      const paymentData = {
        userId: testUserId,
        amount: 100,
        description: '测试积分支付',
        paymentMethod: 'points'
      };

      const result = await paymentProvider.createPayment(paymentData);

      expect(result.success).toBe(true);
      expect(result.data).toHaveProperty('orderId');
      expect(result.data).toHaveProperty('paymentMethod', 'points');
      expect(result.data).toHaveProperty('status', 'completed');
    });

    it('should create wechat payment successfully', async () => {
      const paymentData = {
        userId: testUserId,
        amount: 10.00,
        description: '测试微信支付',
        paymentMethod: 'wechat'
      };

      const result = await paymentProvider.createPayment(paymentData);

      expect(result.success).toBe(true);
      expect(result.data).toHaveProperty('orderId');
      expect(result.data).toHaveProperty('paymentMethod', 'wechat');
      expect(result.data).toHaveProperty('qrCode');
      expect(result.data).toHaveProperty('status', 'pending');
    });

    it('should create alipay payment successfully', async () => {
      const paymentData = {
        userId: testUserId,
        amount: 10.00,
        description: '测试支付宝支付',
        paymentMethod: 'alipay'
      };

      const result = await paymentProvider.createPayment(paymentData);

      expect(result.success).toBe(true);
      expect(result.data).toHaveProperty('orderId');
      expect(result.data).toHaveProperty('paymentMethod', 'alipay');
      expect(result.data).toHaveProperty('qrCode');
      expect(result.data).toHaveProperty('status', 'pending');
    });

    it('should fail with invalid payment method', async () => {
      const paymentData = {
        userId: testUserId,
        amount: 10.00,
        description: '测试无效支付方式',
        paymentMethod: 'invalid'
      };

      const result = await paymentProvider.createPayment(paymentData);

      expect(result.success).toBe(false);
      expect(result.error).toContain('不支持的支付方式');
    });

    it('should fail with invalid amount', async () => {
      const paymentData = {
        userId: testUserId,
        amount: -10.00,
        description: '测试无效金额',
        paymentMethod: 'wechat'
      };

      const result = await paymentProvider.createPayment(paymentData);

      expect(result.success).toBe(false);
      expect(result.error).toContain('无效的金额');
    });
  });

  describe('checkPaymentStatus', () => {
    it('should return correct status for points payment', async () => {
      const result = await paymentProvider.checkPaymentStatus(testOrderId, 'points');

      expect(result.success).toBe(true);
      expect(result.data).toHaveProperty('status');
      expect(['pending', 'completed', 'failed']).toContain(result.data.status);
    });

    it('should return correct status for wechat payment', async () => {
      const result = await paymentProvider.checkPaymentStatus(testOrderId, 'wechat');

      expect(result.success).toBe(true);
      expect(result.data).toHaveProperty('status');
      expect(['pending', 'completed', 'failed']).toContain(result.data.status);
    });

    it('should return correct status for alipay payment', async () => {
      const result = await paymentProvider.checkPaymentStatus(testOrderId, 'alipay');

      expect(result.success).toBe(true);
      expect(result.data).toHaveProperty('status');
      expect(['pending', 'completed', 'failed']).toContain(result.data.status);
    });

    it('should fail with invalid order ID', async () => {
      const result = await paymentProvider.checkPaymentStatus('invalid-order-id', 'wechat');

      expect(result.success).toBe(false);
      expect(result.error).toContain('订单不存在');
    });
  });

  describe('processCallback', () => {
    it('should process wechat callback successfully', async () => {
      const callbackData = {
        orderId: testOrderId,
        paymentMethod: 'wechat',
        status: 'success',
        transactionId: uuidv4()
      };

      const result = await paymentProvider.processCallback(callbackData);

      expect(result.success).toBe(true);
      expect(result.data).toHaveProperty('status', 'completed');
    });

    it('should process alipay callback successfully', async () => {
      const callbackData = {
        orderId: testOrderId,
        paymentMethod: 'alipay',
        status: 'success',
        transactionId: uuidv4()
      };

      const result = await paymentProvider.processCallback(callbackData);

      expect(result.success).toBe(true);
      expect(result.data).toHaveProperty('status', 'completed');
    });

    it('should handle failed callback', async () => {
      const callbackData = {
        orderId: testOrderId,
        paymentMethod: 'wechat',
        status: 'failed',
        errorMessage: '支付失败'
      };

      const result = await paymentProvider.processCallback(callbackData);

      expect(result.success).toBe(true);
      expect(result.data).toHaveProperty('status', 'failed');
    });

    it('should fail with invalid callback data', async () => {
      const callbackData = {
        orderId: 'invalid-order-id',
        paymentMethod: 'wechat',
        status: 'success'
      };

      const result = await paymentProvider.processCallback(callbackData);

      expect(result.success).toBe(false);
      expect(result.error).toContain('订单不存在');
    });
  });

  describe('getSupportedMethods', () => {
    it('should return all supported payment methods', async () => {
      const result = await paymentProvider.getSupportedMethods();

      expect(result.success).toBe(true);
      expect(result.data).toContain('points');
      expect(result.data).toContain('wechat');
      expect(result.data).toContain('alipay');
    });
  });

  describe('validatePaymentData', () => {
    it('should validate correct payment data', () => {
      const paymentData = {
        userId: testUserId,
        amount: 10.00,
        description: '测试支付',
        paymentMethod: 'wechat'
      };

      const result = paymentProvider.validatePaymentData(paymentData);

      expect(result.valid).toBe(true);
    });

    it('should fail validation with missing userId', () => {
      const paymentData = {
        amount: 10.00,
        description: '测试支付',
        paymentMethod: 'wechat'
      };

      const result = paymentProvider.validatePaymentData(paymentData);

      expect(result.valid).toBe(false);
      expect(result.errors).toContain('用户ID不能为空');
    });

    it('should fail validation with invalid amount', () => {
      const paymentData = {
        userId: testUserId,
        amount: 0,
        description: '测试支付',
        paymentMethod: 'wechat'
      };

      const result = paymentProvider.validatePaymentData(paymentData);

      expect(result.valid).toBe(false);
      expect(result.errors).toContain('金额必须大于0');
    });
  });
});
